// Parameterized patterns — matched AFTER an exact TERMS hit fails.
const RULES: { re: RegExp; en: (m: RegExpMatchArray) => string; zh: (m: RegExpMatchArray) => string; ja: (m: RegExpMatchArray) => string }[] = [
  { re: /^총 (.+)$/, en: (m) => `Total ${m[1]}`, zh: (m) => `${m[1]} 总数`, ja: (m) => `${m[1]} の合計` },
  { re: /^(.+) 분포$/, en: (m) => `${m[1]} distribution`, zh: (m) => `${m[1]} 分布`, ja: (m) => `${m[1]} の分布` },
  { re: /^([\d,]+)개 리소스$/, en: (m) => `${m[1]} resources`, zh: (m) => `${m[1]} 个资源`, ja: (m) => `${m[1]} 件のリソース` },
  { re: /^주의 ([\d,]+)건(\+?)$/, en: (m) => `Attention: ${m[1]}${m[2]}`, zh: (m) => `注意 ${m[1]}${m[2]} 项`, ja: (m) => `注意: ${m[1]}${m[2]} 件` },
  { re: /^활성 경고 \((\d+)\)$/, en: (m) => `Active warnings (${m[1]})`, zh: (m) => `活动警告 (${m[1]})`, ja: (m) => `アクティブな警告 (${m[1]})` },
  { re: /^리소스 추세 \((.+)\)$/, en: (m) => `Resource trend (${m[1]})`, zh: (m) => `资源趋势 (${m[1]})`, ja: (m) => `リソース推移 (${m[1]})` },
  { re: /^최근 이벤트 \((\d+)\)$/, en: (m) => `Recent events (${m[1]})`, zh: (m) => `最近事件 (${m[1]})`, ja: (m) => `最近のイベント (${m[1]})` },
  { re: /^(.+) · ([\d,]+)개 리소스$/, en: (m) => `${m[1]} · ${m[2]} resources`, zh: (m) => `${m[1]} · ${m[2]} 个资源`, ja: (m) => `${m[1]} · ${m[2]} 件のリソース` },
  { re: /^공개 접근 가능한 S3 버킷 ([\d,]+)개$/, en: (m) => `${m[1]} publicly accessible S3 buckets`, zh: (m) => `${m[1]} 个可公开访问的 S3 桶`, ja: (m) => `パブリック公開中の S3 バケット ${m[1]} 件` },
  { re: /^인그레스가 개방된 보안 그룹 ([\d,]+)개$/, en: (m) => `${m[1]} security groups with open ingress`, zh: (m) => `${m[1]} 个开放入站的安全组`, ja: (m) => `インバウンドが開放されたセキュリティグループ ${m[1]} 件` },
  { re: /^미암호화 EBS 볼륨 ([\d,]+)개$/, en: (m) => `${m[1]} unencrypted EBS volumes`, zh: (m) => `${m[1]} 个未加密 EBS 卷`, ja: (m) => `未暗号化の EBS ボリューム ${m[1]} 件` },
  { re: /^MFA 미설정 IAM 사용자 ([\d,]+)개$/, en: (m) => `${m[1]} IAM users without MFA`, zh: (m) => `${m[1]} 个未设置 MFA 的 IAM 用户`, ja: (m) => `MFA 未設定の IAM ユーザー ${m[1]} 件` },
  { re: /^실패한 작업 ([\d,]+)개$/, en: (m) => `${m[1]} failed jobs`, zh: (m) => `${m[1]} 个失败任务`, ja: (m) => `失敗したジョブ ${m[1]} 件` },
  { re: /^K8s Warning 이벤트 ([\d,]+)건$/, en: (m) => `${m[1]} K8s warning events`, zh: (m) => `${m[1]} 条 K8s 警告事件`, ja: (m) => `K8s 警告イベント ${m[1]} 件` },
  { re: /^ALARM 상태 CloudWatch 알람 ([\d,]+)개$/, en: (m) => `${m[1]} CloudWatch alarms in ALARM`, zh: (m) => `${m[1]} 个处于 ALARM 的告警`, ja: (m) => `ALARM 状態の CloudWatch アラーム ${m[1]} 件` },
  { re: /^Alarm ([\d,]+)건 · 완료 (.+)$/, en: (m) => `Alarm ${m[1]} · finished ${m[2]}`, zh: (m) => `告警 ${m[1]} · 完成于 ${m[2]}`, ja: (m) => `アラーム ${m[1]} 件 · 完了 ${m[2]}` },
  { re: /^ALARM ([\d,]+)건$/, en: (m) => `ALARM: ${m[1]}`, zh: (m) => `ALARM ${m[1]} 项`, ja: (m) => `ALARM: ${m[1]} 件` },
];

/** Translate a known Korean UI literal (exact match, then patterns). Unknown → unchanged. */
export function applyTerms(lang: Lang, s: string): string {
  if (lang === 'ko') return s;
  const hit = TERMS[s];
  if (hit) return hit[lang];
  for (const r of RULES) {
    const m = s.match(r.re);
    if (m) return r[lang](m);
  }
  return s;
}
